import{_ as a,o,c as r,a3 as t}from"./chunks/framework.aYYe0dfI.js";const g=JSON.parse('{"title":"Module generate","description":"generate 模块负责文档生成的完整流程，包括生成前验证、同步与异步页面构建以及结果输出。它对外提供四个核心函数：generate_dry_run 用于在无副作用的前提下模拟生成过程并返回状态或预估统计；generate_pages 是同步阻塞的入口，接收分析数据、输出路径、并发数及格式标识，在成功时保证输出目录中包含完整且引用一致的文档集；write_pages 将已生成的页面集合写入指定目录；generate_pages_async 则在给定的 kota::event_loop 上执行异步页面生成，调用者必须显式调度返回的任务以触发实际工作。模块内部管理配置、模型、速率限制、页面集合及输出根路径等状态，并依赖 config 模块提供配置数据、依赖 extract 模块提供预处理的符号与分析结果。","frontmatter":{"title":"Module generate","description":"generate 模块负责文档生成的完整流程，包括生成前验证、同步与异步页面构建以及结果输出。它对外提供四个核心函数：generate_dry_run 用于在无副作用的前提下模拟生成过程并返回状态或预估统计；generate_pages 是同步阻塞的入口，接收分析数据、输出路径、并发数及格式标识，在成功时保证输出目录中包含完整且引用一致的文档集；write_pages 将已生成的页面集合写入指定目录；generate_pages_async 则在给定的 kota::event_loop 上执行异步页面生成，调用者必须显式调度返回的任务以触发实际工作。模块内部管理配置、模型、速率限制、页面集合及输出根路径等状态，并依赖 config 模块提供配置数据、依赖 extract 模块提供预处理的符号与分析结果。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/generate/index.md","filePath":"zh/clore/modules/generate/index.md"}'),c={name:"zh/clore/modules/generate/index.md"};function d(n,e,s,i,l,p){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="module-generate" tabindex="-1">Module <code>generate</code> <a class="header-anchor" href="#module-generate" aria-label="Permalink to &quot;Module `generate`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>generate</code> 模块负责文档生成的完整流程，包括生成前验证、同步与异步页面构建以及结果输出。它对外提供四个核心函数：<code>generate_dry_run</code> 用于在无副作用的前提下模拟生成过程并返回状态或预估统计；<code>generate_pages</code> 是同步阻塞的入口，接收分析数据、输出路径、并发数及格式标识，在成功时保证输出目录中包含完整且引用一致的文档集；<code>write_pages</code> 将已生成的页面集合写入指定目录；<code>generate_pages_async</code> 则在给定的 <code>kota::event_loop</code> 上执行异步页面生成，调用者必须显式调度返回的任务以触发实际工作。模块内部管理配置、模型、速率限制、页面集合及输出根路径等状态，并依赖 <code>config</code> 模块提供配置数据、依赖 <code>extract</code> 模块提供预处理的符号与分析结果。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><a href="./../extract/"><code>extract</code></a></li><li><code>std</code></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./../agent/"><code>agent</code></a></li><li><a href="./../agent/tools"><code>agent:tools</code></a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-generate-generate-dry-run" tabindex="-1"><code>clore::generate::generate_dry_run</code> <a class="header-anchor" href="#clore-generate-generate-dry-run" aria-label="Permalink to &quot;`clore::generate::generate_dry_run`&quot;">​</a></h3><p>Declaration: <code>generate/generate.cppm:25</code></p><p>Definition: <code>generate/scheduler.cppm:1888</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p><code>clore::generate::generate_dry_run</code> 首先通过 <code>prepare_generation_context</code> 和 <code>prepare_symbol_analyses_for_dry_run</code> 构建完整的 <code>PreparedGenerationContext</code> 与 <code>PreparedSymbolAnalyses</code>。随后创建一个 <code>PageGenerationScheduler</code> 实例，其构造函数将 <code>dry_run</code> 参数设为 <code>true</code>，并基于给定配置、模型、上下文、LLM 模型、速率限制、输出根路径及事件循环进行初始化。调度器执行 <code>run</code> 方法，遍历所有计划页面：内部会依次调用 <code>run_symbol_analysis_task</code> 与 <code>run_page_prompt_task</code> 来处理依赖分析与提示请求，但干运行模式下 <code>PageRenderer</code> 不会实际执行 <code>emit_pages</code> 或 <code>update_summaries</code> 等含输出写入的操作。<code>DependencyTracker</code> 全程追踪各 <code>PageState</code> 的 <code>unsatisfied_deps</code> 与 <code>completed_prompts</code>，同时 <code>scheduler.expected_llm_requests_</code>、<code>page_prompt_cache_hits_</code> 等计数被累计以反映预期 LLM 调用次数与缓存命中情况。函数最终返回 <code>scheduler.dry_run_pages()</code> 的结果，该值表示干运行中预计生成的页面数量。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>the two const int&amp; parameters</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to simulate generation without side effects</li></ul><h3 id="clore-generate-generate-pages" tabindex="-1"><code>clore::generate::generate_pages</code> <a class="header-anchor" href="#clore-generate-generate-pages" aria-label="Permalink to &quot;`clore::generate::generate_pages`&quot;">​</a></h3><p>Declaration: <code>generate/generate.cppm:28</code></p><p>Definition: <code>generate/scheduler.cppm:1947</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p><code>clore::generate::generate_pages</code> 是页面生成管线的顶层协调函数。它首先调用 <code>prepare_generation_context</code> 从配置与模型参数构建一个 <code>PreparedGenerationContext</code>，其中包含计划集合、提示请求、符号分析目标及链接映射。随后实例化一个 <code>PageGenerationScheduler</code>，传入该上下文、LLM 模型标识、速率限制、输出根目录和事件循环。调度器的 <code>run</code> 方法驱动一个 <code>WorkQueue</code>，该队列区分两类工作项：<code>SymbolAnalysisWork</code>（执行深层符号分析）和 <code>PagePromptWork</code>（根据提示生成页面内容）。一个 <code>DependencyTracker</code> 维护页面间的依赖关系，确保所有必需的符号分析完成后才提交页面的提示请求。提示响应可能从持久缓存（<code>cache_index_</code> 与 <code>prompt_cache_identity_for_page_request</code>）中直接获取，或通过 <code>request_llm_async</code> 发起新的 LLM 调用获取。</p><p>当所有工作项处理完毕，调度器调用 <code>render_generated_pages</code> 将生成的页面写入输出目录，并调用 <code>build_directory_index_pages</code> 生成目录索引页面。整个过程依赖 <code>PageRenderer</code> 执行最终的文件写出与摘要收集，同时通过 <code>record_consecutive_failure</code> 和 <code>fail_page_work</code> 实现错误重试限制，确保在 LLM 调用失败或缓存缺失时不会无限重复。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called as the main generation entry point</li></ul><h3 id="clore-generate-generate-pages-async" tabindex="-1"><code>clore::generate::generate_pages_async</code> <a class="header-anchor" href="#clore-generate-generate-pages-async" aria-label="Permalink to &quot;`clore::generate::generate_pages_async`&quot;">​</a></h3><p>Declaration: <code>generate/generate.cppm:37</code></p><p>Definition: <code>generate/scheduler.cppm:1925</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>该函数的核心实现围绕 <code>PageGenerationScheduler</code> 展开。首先，它使用传入的配置、模型、输出根目录和事件循环构造一个调度器实例，并在内部通过 <code>prepare_generation_context</code> 解析计划与符号分析目标，初始化 <code>DependencyTracker</code> 以追踪页面状态与依赖关系。随后，调度器启动一个多阶段异步流水线：通过 <code>WorkQueue</code> 管理并发工作量，利用 <code>worker_task</code> 循环从队列中取出 <code>ScheduledWork</code> 并执行——工作类型包括符号分析任务（调用 <code>run_symbol_analysis_task</code>）和页面提示任务（调用 <code>run_page_prompt_task</code>）。每个任务完成后会更新依赖状态，并通过 <code>try_submit_ready_pages</code> 将依赖就绪的页面提交为新的提示工作。该过程受 <code>rate_limit</code> 和 <code>consecutive_failures_</code> 控制，确保在 LLM 请求频率和失败重试方面具有可配置的鲁棒性。</p><p>当所有页面提示工作完成后，调度器通过 <code>maybe_stop_workers</code> 终止工作线程，并转入渲染阶段：<code>render_ready_page</code> 收集页面输出并调用 <code>PageRenderer::emit_pages_async</code> 将生成的内容写入文件系统。整个过程完全异步运行在给定的 <code>kota::event_loop</code> 上，调用者需要将返回的任务调度到该循环中并启动执行；函数内部通过 <code>WorkQueue</code> 的信号量（<code>available_</code>）与事件循环协同调度，确保流水线不会阻塞外部循环。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>schedules work on the provided event loop</li><li>potentially writes generated pages to the output location</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>first integer parameter</li><li>second integer parameter</li><li>output path string view</li><li>32-bit integer parameter</li><li>second string view parameter</li><li>event loop reference (for state reading)</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>event loop (by scheduling work)</li><li>generated pages (implied by &#39;page generation&#39;)</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>callers schedule the returned task on the event loop</li><li>run the scheduled task on the loop</li></ul><h3 id="clore-generate-write-pages" tabindex="-1"><code>clore::generate::write_pages</code> <a class="header-anchor" href="#clore-generate-write-pages" aria-label="Permalink to &quot;`clore::generate::write_pages`&quot;">​</a></h3><p>Declaration: <code>generate/generate.cppm:44</code></p><p>Definition: <code>generate/scheduler.cppm:1966</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function <code>clore::generate::write_pages</code> orchestrates the end-to-end generation of documentation pages. It first prepares the generation context by calling <code>prepare_generation_context</code>, which builds the collection of documentable symbols and prompt requests. A <code>PageGenerationScheduler</code> is then instantiated with the configuration, LLM model, <code>PreparedGenerationContext</code>, output root, event loop, and optional dry-run flag. The scheduler’s <code>run</code> method drives the core workflow: it initializes <code>DependencyTracker</code>, submits symbol analysis tasks and page prompt requests via <code>submit_after_symbol_analysis</code> and <code>schedule_symbol_analysis</code>, and processes the asynchronous work queue (<code>WorkQueue</code>) through worker tasks. Each worker invocation of <code>worker_task</code> polls the queue, runs <code>run_symbol_analysis_task</code> or <code>run_page_prompt_task</code>, and updates state through the tracker. After LLM requests complete, the scheduler calls <code>render_ready_page</code> to generate final output via <code>PageRenderer::emit_pages_async</code> and <code>render_generated_pages</code>. The function returns a status code indicating success or failure, with metrics gathered from the scheduler’s counters (<code>llm_requests_issued_</code>, <code>written_output_count_</code>, etc.).</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Writes documentation pages to the filesystem</li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>The integer parameter (likely a page plan set identifier)</li><li>The string view parameter (likely an output path)</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Files on disk</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called during documentation generation to write all pages</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p><code>generate</code>模块按照功能关注点进行了清晰的分解：提供干运行验证、同步生成、独立写出以及异步生成四项公开入口，分别对应 <code>generate_dry_run</code>、<code>generate_pages</code>、<code>write_pages</code> 和 <code>generate_pages_async</code>。这些函数共享同一声明单元（<code>generate.cppm</code>）内的一组内部变量，包括配置对象、LLM 模型句柄、速率限制参数以及页面容器，从而在避免重复声明的同时保持状态一致性。模块显式导入 <code>config</code>（读取外部设置）、<code>extract</code>（利用已提取的符号数据）以及标准库，未引入其他业务模块，体现了向下的依赖方向。内部层次上，同步流程（<code>generate_pages</code> → 隐式构建页面计划 → 可选调用 <code>write_pages</code> 落盘）与异步流程（<code>generate_pages_async</code> 接受 <code>kota::event_loop</code> 引用，将生成任务调度到循环之上）并行存在，前者阻塞直至完成，后者将生命周期交给调用者控制。干运行函数则独立模拟完整流程但不产生输出，方便调用者评估生成范围与成本。这种结构使调用方可根据场景选择同步或异步路径，同时通过公开的写出函数将页面渲染与序列化解耦。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li><li><a href="./../extract/">Module extract</a></li></ul>',60)])])}const h=a(c,[["render",d]]);export{g as __pageData,h as default};
